Icarus Verilog version 0.10.0 (devel) (s20150603-55-g97c6339)
cygwin, gcc-4.8.3
# the following is bench file.

module  test (

output reg  MPC_LCLK,  
output reg  MPC_LALE,   

output reg [7:0] MPC_LA,  
inout      [7:0] MPC_LAD  
);

reg    [7:0]  mpc_address;

assign  MPC_LAD   = (MPC_LALE  == 1'b1) ? mpc_address : 8'hz;

initial begin
    MPC_LCLK  =  0;
    MPC_LALE  =  0;
    mpc_address =  0;
end

always #15 MPC_LCLK = !MPC_LCLK;

task  foo;
input  [16:0]  address;

begin
    @(posedge MPC_LCLK)
    mpc_address = address[15:8];
    MPC_LA = address[7:0];
    MPC_LALE = 1;
    @(posedge MPC_LCLK)
    MPC_LALE = 0;
end

endtask

reg [15:0]  addr;

always @(posedge MPC_LCLK)
    begin
        addr <= {MPC_LAD, MPC_LA};
    end

integer  i;
initial begin
    //$dumpfile("test.vcd"); 
    //$dumpvars(0, test);
    $monitor($time, " : %h %h : %h %h", MPC_LAD, MPC_LA, MPC_LALE, addr);
    #100 foo(4);
    #100 $finish;
end

endmodule
